local function check_role(role)
    return role == 'admin' or role == 'user' or role == 'anonymous'
end


function access(conf, var)

    if ngx.var.uri:match("/admin") ~= nil then
        return true
    end

    local auth = ngx.req.get_headers()["Authorization"]

    -- If no authorization header is sent then skip
    if not auth or #auth == 0 then 
        return false 
    end 

    for _, v in ipairs(conf) do
        local token, role = v:match("([^%s]+)%s+(.+)")

        if check_role(role) and (auth ~= nil and auth ~= "" )then
            -- Check that the Authorization header contains a bearer token
            local bearer = auth:match("^bearer (.+)$")

            if bearer == token then
                return true 
            end
        else
           ngx.exit(ngx.HTTP_FORBIDDEN);
        end
    end
    return false
end


function access_by_lua()
    if access({
        [1] = "<KEY> <KEY>",
    }) then 
        return
    else 
       ngx.exit(ngx.HTTP_UNAUTHORIZED) 
